import { Request, Response } from 'express';
import { Status, Messages } from '../common/constants';

import { JobSite, IJobSite } from '../models/JobSite';
import { JobLocation } from '../models/JobLocation';
import * as Sentry from '@sentry/node';
import escapeStringRegexp from 'escape-string-regexp';
import { Types } from 'mongoose';

const ADDRESS_FIELDS = ['street', 'city', 'state', 'zipcode'];

const hasValue = (value: any): boolean => value !== undefined && value !== null && value !== '';

const getAddressInput = (params: any): any => {
    const source = params.address && typeof params.address === 'object' ? params.address : params;
    const address: any = {};

    ADDRESS_FIELDS.forEach((field) => {
        if (source[field] !== undefined && source[field] !== null) {
            address[field] = source[field];
        }
    });

    return Object.keys(address).length ? address : null;
};

const hasAddressData = (address: any): boolean => {
    if (!address) {
        return false;
    }

    return ADDRESS_FIELDS.some((field) => {
        const value = address[field];
        return typeof value === 'string' ? value.trim() !== '' : hasValue(value);
    });
};

const getCoordinates = (params: any): number[] | null => {
    const location = params.location || {};
    const lat = location.lat ?? params.locationLat ?? params.lat;
    const long = location.long ?? location.lng ?? params.locationLong ?? params.long ?? params.lng;

    if (!hasValue(lat) || !hasValue(long)) {
        return null;
    }

    const latitude = Number(lat);
    const longitude = Number(long);

    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) {
        return null;
    }

    return [longitude, latitude];
};

const getFirstId = (value: any): any => Array.isArray(value) ? value[0] : value;

const getJobLocationOwnership = (jobLocation: any): { customerId?: any, homeOwner?: any } => {
    const customerId = getFirstId(jobLocation?.customerIds) || jobLocation?.customerId;
    const homeOwner = jobLocation?.homeOwner || jobLocation?.homeOwnerId;

    return { customerId, homeOwner };
};

const sameId = (first: any, second: any): boolean => String(first || '') === String(second || '');

const parseIsActive = (submittedIsActive: any): boolean => {
    return submittedIsActive === 'false' || submittedIsActive === '0'
        ? false
        : !!submittedIsActive;
};

const mergeAddress = (existingAddress: any, submittedAddress: any): any => {
    const nextAddress = { ...(existingAddress || {}) };

    ADDRESS_FIELDS.forEach((field) => {
        if (submittedAddress[field] !== undefined && submittedAddress[field] !== null) {
            nextAddress[field] = submittedAddress[field];
        }
    });

    return nextAddress;
};


export const get = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { query: queryParams = {} } = req;
    const { customerId, homeOwnerId, locationId, isActive } = queryParams;

    console.log('Query Params:', queryParams);

    let query: {
        _id?: string;
        customerId?: string;
        locationId?: Types.ObjectId;
        homeOwner?: string;
        $or?: Array<{[key: string]: any}>;
        isActive?: boolean;
    } = {};

    if (id) {
        query = { _id: id };
    } else if (customerId && locationId) {
        query = { customerId, locationId: new Types.ObjectId(locationId) };
    } else if (homeOwnerId && locationId) {
        query = { homeOwner: homeOwnerId, locationId: new Types.ObjectId(locationId) };
    } else if (customerId && !homeOwnerId) {
        query = { customerId };
    } else if (customerId && homeOwnerId) {
        query = { $or: [{ customerId }, { homeOwner: homeOwnerId }] };
    } else if (homeOwnerId && !customerId) {
        query = { homeOwner: homeOwnerId };
    } else if (locationId) {
        query = { locationId: new Types.ObjectId(locationId) };
    } 

    switch (isActive) {
        case 'true':
        case true:
            query = {...query, $or: [...(query.$or || []), { isActive: true }, { isActive: { $exists: false } }] };
