            const locationId = new Types.ObjectId();
            const customerId = new Types.ObjectId();
            const jobSiteId = new Types.ObjectId();
            const address = {
                street: '100 Main St',
                city: 'Austin',
                state: 'TX',
                zipcode: '78701'
            };
            const createdJobSite = { _id: jobSiteId, name: 'Lot 12' };
