                name: 'Lot 12',
                locationId: locationId.toHexString(),
                address
            };

            const findLocationStub = sinon.stub(JobLocation as any, 'findById').resolves({
                _id: locationId,
                customerIds: [customerId]
            });
            const findDuplicateStub = sinon.stub(JobSite as any, 'findOne').resolves(null);
            const createStub = sinon.stub(JobSite as any, 'create').resolves(createdJobSite);
            const pushStub = sinon.stub(JobLocation as any, 'findByIdAndUpdate').resolves({});

