            const createArg = createStub.firstCall.args[0];
            expect(createArg.name).to.equal('Lot 12');
            expect(createArg.locationId).to.equal(locationId.toHexString());
            expect(createArg.address).to.deep.equal(address);
            expect(createArg).to.not.have.property('location');
            expect(String(createArg.customerId)).to.equal(String(customerId));

            expect(pushStub.calledWith(locationId.toHexString(), { $push: { jobSites: jobSiteId } })).to.be.true;
            expect(statusStub.calledWith(Status.OK)).to.be.true;
            expect(jsonStub.calledWith(createdJobSite)).to.be.true;
        });

        it('rejects creates with neither coordinates nor address data', async () => {
            req.body = {
                name: 'Lot 12',
                locationId: new Types.ObjectId().toHexString()
            };
            const findLocationStub = sinon.stub(JobLocation as any, 'findById');

            await create(req as Request, res as Response);

            expect(findLocationStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Either location or address is required.'
            })).to.be.true;
        });

        it('rejects duplicate job address names within the same subdivision', async () => {
            const locationId = new Types.ObjectId();
            const customerId = new Types.ObjectId();
            req.body = {
                name: 'Lot 12',
                locationId: locationId.toHexString(),
                location: {
                    lat: 30.2672,
                    long: -97.7431
                }
            };

            sinon.stub(JobLocation as any, 'findById').resolves({
                _id: locationId,
                customerIds: [customerId]
            });
            const findDuplicateStub = sinon.stub(JobSite as any, 'findOne').resolves({ _id: new Types.ObjectId() });
            const createStub = sinon.stub(JobSite as any, 'create');

            await create(req as Request, res as Response);

            expect(findDuplicateStub.calledWith({ locationId: locationId.toHexString(), name: 'Lot 12' })).to.be.true;
            expect(createStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Job Address already exists.'
            })).to.be.true;
        });
    });

    describe('update', () => {
        it('preserves optional address, location, owner, and active fields when omitted', async () => {
            const siteId = new Types.ObjectId();
            const locationId = new Types.ObjectId();
            const customerId = new Types.ObjectId();
            const homeOwner = new Types.ObjectId();
