            expect(updateStub.firstCall.args[0]).to.deep.equal({ _id: siteId.toHexString() });
            expect(updateStub.firstCall.args[1]).to.deep.equal({ $set: { name: 'Lot 12A' } });
            expect(jsonStub.calledWith({
