            });
            const findDuplicateStub = sinon.stub(JobSite as any, 'findOne').resolves({ _id: new Types.ObjectId() });
            const updateStub = sinon.stub(JobSite as any, 'updateOne');

            await update(req as Request, res as Response);

            expect(findDuplicateStub.calledWith({
                _id: { $ne: siteId.toHexString() },
                locationId,
                name: 'Lot 13'
            })).to.be.true;
            expect(updateStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Job Address already exists.'
            })).to.be.true;
        });
    });
});

